import { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { contentApi } from '../../services/api';
import { useNotify } from '../../hooks/useNotify';
import MediaUpload from '../../components/admin/MediaUpload';
import '../Admin.css';

const INITIAL = {
  title: '',
  description: '',
  video: null,
  thumbnail: null,
  duration: '',
  featured: false,
  trending: false,
};

export default function UploadVideo() {
  const [form, setForm] = useState(INITIAL);
  const [saving, setSaving] = useState(false);
  const navigate = useNavigate();
  const notify = useNotify();

  const videoUrl = form.video?.url;
  const thumbnailUrl = form.thumbnail?.url || form.video?.thumbnail;

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!videoUrl) {
      notify.error('Please upload a video file');
      return;
    }

    setSaving(true);
    try {
      await contentApi.create({
        type: 'video',
        title: form.title,
        description: form.description,
        thumbnail: thumbnailUrl || '',
        videoUrl,
        duration: form.video?.duration ?? (form.duration ? parseInt(form.duration, 10) : undefined),
        featured: form.featured,
        trending: form.trending,
      });
      notify.success('Video published successfully');
      navigate('/admin/videos');
    } catch (err) {
      notify.error(err.message);
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="dash-page">
      <div className="dash-page__header">
        <div>
          <Link to="/admin/videos" className="dash-breadcrumb">← Back to Videos</Link>
          <h1>Upload Video</h1>
          <p>Upload a video file — stored on Cloudinary</p>
        </div>
      </div>

      <form className="upload-form" onSubmit={handleSubmit}>
        <div className="upload-form__grid">
          <div className="upload-form__main">
            <div className="upload-form__section">
              <h2>Video File</h2>
              <MediaUpload
                type="video"
                accept="video/mp4,video/webm,video/quicktime,video/*"
                hint="MP4, WebM, MOV — max 200MB"
                value={form.video}
                previewType="video"
                onChange={(video) => {
                  if (video?.error) {
                    notify.error(video.error);
                    return;
                  }
                  setForm((prev) => ({
                    ...prev,
                    video,
                    duration: video?.duration ? String(video.duration) : prev.duration,
                    thumbnail: video?.thumbnail && !prev.thumbnail?.url
                      ? { url: video.thumbnail }
                      : prev.thumbnail,
                  }));
                }}
              />
            </div>

            <div className="upload-form__section">
              <h2>Video Details</h2>
              <label>
                Title <span className="required">*</span>
                <input
                  value={form.title}
                  onChange={(e) => setForm({ ...form, title: e.target.value })}
                  placeholder="Enter video title"
                  required
                />
              </label>
              <label>
                Description
                <textarea
                  value={form.description}
                  onChange={(e) => setForm({ ...form, description: e.target.value })}
                  placeholder="Short description for the video"
                  rows={4}
                />
              </label>
            </div>
          </div>

          <div className="upload-form__side">
            <div className="upload-form__section">
              <h2>Thumbnail</h2>
              <MediaUpload
                type="image"
                accept="image/jpeg,image/png,image/webp,image/*"
                hint="Optional — auto-generated from video if skipped"
                value={form.thumbnail || (thumbnailUrl ? { url: thumbnailUrl } : null)}
                onChange={(thumbnail) => {
                  if (thumbnail?.error) {
                    notify.error(thumbnail.error);
                    return;
                  }
                  setForm({ ...form, thumbnail });
                }}
              />
            </div>

            <div className="upload-form__section">
              <h2>Settings</h2>
              <label>
                Duration (seconds)
                <input
                  type="number"
                  min="0"
                  value={form.duration}
                  onChange={(e) => setForm({ ...form, duration: e.target.value })}
                  placeholder="Auto-filled after upload"
                  readOnly={Boolean(form.video?.duration)}
                />
              </label>
              <label className="upload-checkbox">
                <input
                  type="checkbox"
                  checked={form.featured}
                  onChange={(e) => setForm({ ...form, featured: e.target.checked })}
                />
                Mark as Featured
              </label>
              <label className="upload-checkbox">
                <input
                  type="checkbox"
                  checked={form.trending}
                  onChange={(e) => setForm({ ...form, trending: e.target.checked })}
                />
                Mark as Trending
              </label>
            </div>

            <button
              type="submit"
              className="btn btn-primary upload-form__submit"
              disabled={saving || !videoUrl}
            >
              {saving ? 'Publishing...' : 'Publish Video'}
            </button>
          </div>
        </div>
      </form>
    </div>
  );
}
